import React, { useState } from 'react';
import { uploadToCloudinary } from '../utils/cloudinary';

export default function AddUserForm({ onUserAdded }) {
  const [form, setForm] = useState({
    name: '',
    email: '',
    phoneNumber: '',
    nic: '',
    password: '',
    dateOfBirth: '',
    school: '',
  });
  const [profilePic, setProfilePic] = useState(null);
  const [loading, setLoading] = useState(false);
  const [errors, setErrors] = useState({});
  const [assignedId, setAssignedId] = useState('');
  const [age, setAge] = useState('');

  const handleChange = e => {
    setForm({ ...form, [e.target.name]: e.target.value });
    if (e.target.name === 'dateOfBirth') {
      const dob = new Date(e.target.value);
      const today = new Date();
      let calculatedAge = today.getFullYear() - dob.getFullYear();
      const m = today.getMonth() - dob.getMonth();
      if (m < 0 || (m === 0 && today.getDate() < dob.getDate())) {
        calculatedAge--;
      }
      setAge(calculatedAge > 0 ? calculatedAge : '');
    }
  };

  const handleFileChange = e => {
    setProfilePic(e.target.files[0] || null);
  };

  const validate = () => {
    const errs = {};
    if (!form.name) errs.name = 'Please enter Name';
    if (!form.email) errs.email = 'Please enter Email';
    if (!form.phoneNumber) errs.phoneNumber = 'Please enter Phone Number';
    if (!form.nic) errs.nic = 'Please enter NIC';
    if (!form.password) errs.password = 'Please enter Password';
    if (!form.dateOfBirth) errs.dateOfBirth = 'Please enter Date of Birth';
    if (!form.school) errs.school = 'Please enter School';
    return errs;
  };

  const onSubmit = async e => {
    e.preventDefault();
    const errs = validate();
    setErrors(errs);
    if (Object.keys(errs).length > 0) return;
    setLoading(true);
    try {
      let profilePicUrl = '';
      if (profilePic) {
        profilePicUrl = await uploadToCloudinary(profilePic);
      }
      const token = localStorage.getItem('token');
      const res = await fetch(`${process.env.REACT_APP_API_URL || ''}/api/users`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`,
        },
        body: JSON.stringify({ ...form, profilePic: profilePicUrl }),
      });
      const data = await res.json();
      if (res.ok) {
        alert('User added!');
        setAssignedId(data.user._id);
        setForm({ name: '', email: '', phoneNumber: '', nic: '', password: '', dateOfBirth: '', school: '' });
        setAge('');
        setProfilePic(null);
        setErrors({});
        if (onUserAdded) onUserAdded(data.user);
      } else {
        alert(data.message || 'Failed to add user');
      }
    } catch (err) {
      alert('Failed to add user');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{ maxWidth: 600, margin: '0 auto', background: '#fff', borderRadius: 8, padding: 24, boxShadow: '0 2px 12px #e6f7ff' }}>
      <h2>Add New User</h2>
      <form onSubmit={onSubmit} autoComplete="off">
        {assignedId && (
          <div style={{ marginBottom: 16 }}>
            <label>Assigned ID</label><br />
            <input name="id" value={assignedId} readOnly style={{ width: '100%', padding: 8, background: '#f5f5f5' }} />
          </div>
        )}
        <div style={{ marginBottom: 16 }}>
          <label>Name *</label><br />
          <input name="name" value={form.name} onChange={handleChange} style={{ width: '100%', padding: 8 }} />
          {errors.name && <div style={{ color: 'red' }}>{errors.name}</div>}
        </div>
        <div style={{ marginBottom: 16 }}>
          <label>Email *</label><br />
          <input name="email" type="email" value={form.email} onChange={handleChange} style={{ width: '100%', padding: 8 }} />
          {errors.email && <div style={{ color: 'red' }}>{errors.email}</div>}
        </div>
        <div style={{ marginBottom: 16 }}>
          <label>Phone Number *</label><br />
          <input name="phoneNumber" value={form.phoneNumber} onChange={handleChange} style={{ width: '100%', padding: 8 }} />
          {errors.phoneNumber && <div style={{ color: 'red' }}>{errors.phoneNumber}</div>}
        </div>
        <div style={{ marginBottom: 16 }}>
          <label>NIC *</label><br />
          <input name="nic" value={form.nic} onChange={handleChange} style={{ width: '100%', padding: 8 }} />
          {errors.nic && <div style={{ color: 'red' }}>{errors.nic}</div>}
        </div>
        <div style={{ marginBottom: 16 }}>
          <label>Password *</label><br />
          <input name="password" type="password" value={form.password} onChange={handleChange} style={{ width: '100%', padding: 8 }} />
          {errors.password && <div style={{ color: 'red' }}>{errors.password}</div>}
        </div>
        <div style={{ marginBottom: 16 }}>
          <label>Date of Birth *</label><br />
          <input name="dateOfBirth" type="date" value={form.dateOfBirth} onChange={handleChange} style={{ width: '100%', padding: 8 }} />
          {errors.dateOfBirth && <div style={{ color: 'red' }}>{errors.dateOfBirth}</div>}
        </div>
        <div style={{ marginBottom: 16 }}>
          <label>Age</label><br />
          <input name="age" value={age} readOnly style={{ width: '100%', padding: 8, background: '#f5f5f5' }} />
        </div>
        <div style={{ marginBottom: 16 }}>
          <label>School *</label><br />
          <select name="school" value={form.school} onChange={handleChange} style={{ width: '100%', padding: 8 }}>
            <option value="">Select School</option>
            <option value="J/Jaffna Central College">J/Jaffna Central College</option>
            <option value="J/Passaioor St Antony's Girls Vid">J/Passaioor St Antony's Girls Vid</option>
            <option value="J/St John's College">J/St John's College</option>
            <option value="J/Kondavil RCTM School">J/Kondavil RCTM School</option>
            <option value="J/Jaffna Hindu College">J/Jaffna Hindu College</option>
            <option value="J/Osmania College">J/Osmania College</option>
            <option value="J/St Patrick's College">J/St Patrick's College</option>
            <option value="J/Poompukar GTMS">J/Poompukar GTMS</option>
            <option value="J/Vaidyeshwara College">J/Vaidyeshwara College</option>
            <option value="J/Nallur Kasipillai Vidalayam">J/Nallur Kasipillai Vidalayam</option>
            <option value="J/Kokuvil Hindu College">J/Kokuvil Hindu College</option>
            <option value="J/Kokuvil West CCTM School">J/Kokuvil West CCTM School</option>
            <option value="J/Urapulam MV">J/Urapulam MV</option>
            <option value="J/St James Maha Vidyalayam">J/St James Maha Vidyalayam</option>
            <option value="J/Kokuvil East Namakal Vidyalayam">J/Kokuvil East Namakal Vidyalayam</option>
            <option value="J/Kokuvil Sthana CCTM School">J/Kokuvil Sthana CCTM School</option>
            <option value="J/Canagaratnam MMV">J/Canagaratnam MMV</option>
            <option value="J/Ariyalai Sri Parwathy Vidyalayam">J/Ariyalai Sri Parwathy Vidyalayam</option>
            <option value="J/Columbuththurai Hindu MV">J/Columbuththurai Hindu MV</option>
            <option value="J/Hindu Ladies Primary School">J/Hindu Ladies Primary School</option>
            <option value="J/St John Bosco Vid">J/St John Bosco Vid</option>
            <option value="J/Delft MV">J/Delft MV</option>
            <option value="J/Vannai Navalar MV">J/Vannai Navalar MV</option>
            <option value="J/Mavilithurai RCTM Vidyalayam">J/Mavilithurai RCTM Vidyalayam</option>
            <option value="J/Jaffna Hindu Primary School">J/Jaffna Hindu Primary School</option>
            <option value="J/Delft Seekkiriyampallam GTMS">J/Delft Seekkiriyampallam GTMS</option>
            <option value="J/Kokuvil Hindu Primary School">J/Kokuvil Hindu Primary School</option>
            <option value="J/Delft RC Vidyalayam">J/Delft RC Vidyalayam</option>
            <option value="J/Koddady Namasivaya Vid">J/Koddady Namasivaya Vid</option>
            <option value="J/Delft Mankaiyatkarasi Vidyalayam">J/Delft Mankaiyatkarasi Vidyalayam</option>
            <option value="J/Kokuvil Sri Ramakrina Vidyasalai">J/Kokuvil Sri Ramakrina Vidyasalai</option>
            <option value="J/Delft Subramaniyam Vidyalayam">J/Delft Subramaniyam Vidyalayam</option>
            <option value="J/Kondavil Ramakrishna Vid">J/Kondavil Ramakrishna Vid</option>
            <option value="J/Delft Saivapiragasa Vidyalayam">J/Delft Saivapiragasa Vidyalayam</option>
            <option value="J/Thirunelvely RCTMS">J/Thirunelvely RCTMS</option>
            <option value="J/Delft Sriskantha Vidyalayam">J/Delft Sriskantha Vidyalayam</option>
            <option value="J/Nallur Anipanthi MMV">J/Nallur Anipanthi MMV</option>
            <option value="J/St James Girls Maha Vidyalayam">J/St James Girls Maha Vidyalayam</option>
            <option value="J/Chedditheru MMTM School">J/Chedditheru MMTM School</option>
            <option value="J/Nallur St Benedict RCV">J/Nallur St Benedict RCV</option>
            <option value="J/Parameswara VID">J/Parameswara VID</option>
            <option value="J/Kalviyankadu HTMS">J/Kalviyankadu HTMS</option>
            <option value="J/Kondavil CCTM School">J/Kondavil CCTM School</option>
          </select>
          {errors.school && <div style={{ color: 'red' }}>{errors.school}</div>}
        </div>
        <div style={{ marginBottom: 16 }}>
          <label>Profile Photo</label><br />
          <input type="file" accept="image/*" onChange={handleFileChange} />
          {profilePic && <div style={{ marginTop: 8 }}>{profilePic.name}</div>}
        </div>
        <button type="submit" disabled={loading} style={{ padding: '8px 24px', background: '#1677ff', color: '#fff', border: 'none', borderRadius: 4 }}>
          {loading ? 'Adding...' : 'Add User'}
        </button>
      </form>
    </div>
  );
}
